const docData    = $json;
const prep       = $('SES: Підготовка Docs').first().json;
const docId      = prep.docId;
const imageUrls  = prep.image_urls  || {};
const imageSizes = prep.image_sizes || {};

const tab0Content = docData.tabs?.[0]?.documentTab?.body?.content || [];
const bodyContent = docData.body?.content || [];
const content     = tab0Content.length > 0 ? tab0Content : bodyContent;

function findInContent(elems, placeholder) {
  const results = [];
  for (const el of elems) {
    if (el.paragraph) {
      for (const e of (el.paragraph.elements || [])) {
        if (!e.textRun) continue;
        const text = e.textRun.content || '';
        let idx = text.indexOf(placeholder);
        while (idx >= 0) {
          results.push({
            startIndex: e.startIndex + idx,
            endIndex:   e.startIndex + idx + placeholder.length
          });
          idx = text.indexOf(placeholder, idx + 1);
        }
      }
    } else if (el.table) {
      for (const row of (el.table.tableRows || [])) {
        for (const cell of (row.tableCells || [])) {
          results.push(...findInContent(cell.content || [], placeholder));
        }
      }
    }
  }
  return results;
}

const imagePositions = [];
for (const [placeholder, url] of Object.entries(imageUrls)) {
  if (!url) continue;
  const found = findInContent(content, placeholder);
  for (const pos of found) {
    imagePositions.push({ placeholder, url, ...pos });
  }
}

// Зворотній порядок: спочатку пізніші позиції, щоб делети не зсунули ранніші
imagePositions.sort((a, b) => b.startIndex - a.startIndex);

const requests = [];
for (const { placeholder, url, startIndex, endIndex } of imagePositions) {
  const size = imageSizes[placeholder] || { width: 400, height: 250 };
  requests.push({
    deleteContentRange: { range: { startIndex, endIndex } }
  });
  requests.push({
    insertInlineImage: {
      uri: url,
      objectSize: {
        width:  { magnitude: size.width,  unit: 'PT' },
        height: { magnitude: size.height, unit: 'PT' }
      },
      location: { index: startIndex }
    }
  });
}

return [{ json: { docId, requests, ...prep } }];

